    ARRAY[E'area'],
    E'Andy Kriebel',
    E'https://public.tableau.com/app/profile/andy.kriebel',
    E'Embedded from Tableau Public. All rights to the original author. Commentary by TableauKit.',
    null,
    null,
    E'An area chart is a line chart with the area below filled. Adds visual weight to magnitude. Use them for *stacked* area when showing total + composition over time (revenue stacked by product line). Standalone area charts (one fill) rarely add anything over a line — the fill takes ink without adding meaning. The trap with stacked area: when one series dominates, the others become invisible squiggles at the top. Switch to 100% stacked area when you want to see *composition* rather than absolute totals.',
    null,
    2,
    true,
    now()
